//
// Set cell value and cell formula for a worksheet with stream writer:
//
//	err := sw.SetRow("A1", []interface{}{
//	    excelize.Cell{Value: 1},
//	    excelize.Cell{Value: 2},
//	    excelize.Cell{Formula: "SUM(A1,B1)"}});
//
// Set cell value and rows style for a worksheet with stream writer:
//
//	err := sw.SetRow("A1", []interface{}{
//	    excelize.Cell{Value: 1}},
//	    excelize.RowOpts{StyleID: styleID, Height: 20, Hidden: false});
func (f *File) NewStreamWriter(sheet string) (*StreamWriter, error) {
	if err := checkSheetName(sheet); err != nil {
		return nil, err
	}
	sheetID := f.getSheetID(sheet)
	if sheetID == -1 {
		return nil, ErrSheetNotExist{sheet}
	}
	chunkSize := f.options.StreamingChunkSize
	if chunkSize <= 0 {
		chunkSize = StreamChunkSize
	}
	bufSize := f.options.StreamingBufSize
	if bufSize <= 0 {
		bufSize = StreamingBufSizeDefault
	}
	sw := &StreamWriter{
		file:    f,
		Sheet:   sheet,
		SheetID: sheetID,
		rawData: bufferedWriter{
			tmpDir:    f.options.TmpDir,
			flushSize: chunkSize,
			bioSize:   bufSize,
		},
	}
	var err error
	sw.worksheet, err = f.workSheetReader(sheet)
	if err != nil {
		return nil, err
	}

	sheetXMLPath, _ := f.getSheetXMLPath(sheet)
	if f.streams == nil {
		f.streams = make(map[string]*StreamWriter)
	}
	f.streams[sheetXMLPath] = sw

	_, _ = sw.rawData.WriteString(xml.Header + `<worksheet` + templateNamespaceIDMap)
	bulkAppendFields(&sw.rawData, sw.worksheet, 3, 4)
	return sw, err
}

// AddTable creates an Excel table for the StreamWriter using the given
// cell range and format set. For example, create a table of A1:D5:
//
//	err := sw.AddTable(&excelize.Table{Range: "A1:D5"})
//
// Create a table of F2:H6 with format set:
//
//	disable := false
//	err := sw.AddTable(&excelize.Table{
//	    Range:             "F2:H6",
//	    Name:              "table",
//	    StyleName:         "TableStyleMedium2",
//	    ShowFirstColumn:   true,
//	    ShowLastColumn:    true,
//	    ShowRowStripes:    &disable,
//	    ShowColumnStripes: true,
//	})
//
// Note that the table must be at least two lines including the header. The
// header cells must contain strings and must be unique.
//
// Currently, only one table is allowed for a StreamWriter. AddTable must be
// called after the rows are written but before Flush.
//
// See File.AddTable for details on the table format.
func (sw *StreamWriter) AddTable(table *Table) error {
	options, err := parseTableOptions(table)
	if err != nil {
		return err
	}
	coordinates, err := rangeRefToCoordinates(options.Range)
	if err != nil {
		return err
	}
	_ = sortCoordinates(coordinates)

	// Correct the minimum number of rows, the table at least two lines.
	if coordinates[1] == coordinates[3] {
		coordinates[3]++
	}

	// Correct table reference range, such correct C1:B3 to B1:C3.
	ref, err := coordinatesToRangeRef(coordinates)
	if err != nil {
		return err
	}

	// create table columns using the first row
	tableHeaders, err := sw.getRowValues(coordinates[1], coordinates[0], coordinates[2])
	if err != nil {
		return err
	}
	tableColumn := make([]*xlsxTableColumn, len(tableHeaders))
	for i, name := range tableHeaders {
		tableColumn[i] = &xlsxTableColumn{
			ID:   i + 1,
			Name: name,
		}
	}

	tableID := sw.file.countTables() + 1

	name := options.Name
	if name == "" {
		name = "Table" + strconv.Itoa(tableID)
	}

	tbl := xlsxTable{
		XMLNS:       NameSpaceSpreadSheet.Value,
		ID:          tableID,
		Name:        name,
		DisplayName: name,
		Ref:         ref,
		AutoFilter: &xlsxAutoFilter{
			Ref: ref,
		},
		TableColumns: &xlsxTableColumns{
			Count:       len(tableColumn),
			TableColumn: tableColumn,
		},
		TableStyleInfo: &xlsxTableStyleInfo{
			Name:              options.StyleName,
			ShowFirstColumn:   options.ShowFirstColumn,
			ShowLastColumn:    options.ShowLastColumn,
			ShowRowStripes:    *options.ShowRowStripes,
			ShowColumnStripes: options.ShowColumnStripes,
		},
	}

	sheetRelationshipsTableXML := "../tables/table" + strconv.Itoa(tableID) + ".xml"
	tableXML := strings.ReplaceAll(sheetRelationshipsTableXML, "..", "xl")

	// Add first table for given sheet
	sheetPath := sw.file.sheetMap[sw.Sheet]
	sheetRels := "xl/worksheets/_rels/" + strings.TrimPrefix(sheetPath, "xl/worksheets/") + ".rels"
	rID := sw.file.addRels(sheetRels, SourceRelationshipTable, sheetRelationshipsTableXML, "")

	sw.tableParts = fmt.Sprintf(`<tableParts count="1"><tablePart r:id="rId%d"></tablePart></tableParts>`, rID)

	if err = sw.file.addContentTypePart(tableID, "table"); err != nil {
		return err
	}
	b, _ := xml.Marshal(tbl)
	sw.file.saveFileList(tableXML, b)
	return err
}

// Extract values from a row in the StreamWriter.
func (sw *StreamWriter) getRowValues(hRow, hCol, vCol int) (res []string, err error) {
	res = make([]string, vCol-hCol+1)

	r, err := sw.rawData.Reader()
	if err != nil {
		return nil, err
	}

	dec := sw.file.xmlNewDecoder(r)
	for {
		token, err := dec.Token()
		if err == io.EOF {
			return res, nil
		}
		if err != nil {
			return nil, err
		}
		startElement, ok := getRowElement(token, hRow)
		if !ok {
			continue
		}
		// decode cells
		var row xlsxRow
		if err := dec.DecodeElement(&row, &startElement); err != nil {
			return nil, err
		}
		for _, c := range row.C {
			col, _, err := CellNameToCoordinates(c.R)
			if err != nil {
				return nil, err
			}
			if col < hCol || col > vCol {
				continue
			}
			res[col-hCol], _ = c.getValueFrom(sw.file, nil, false)
		}
		return res, nil
	}
}

// Check if the token is an worksheet row with the matching row number.
func getRowElement(token xml.Token, hRow int) (startElement xml.StartElement, ok bool) {
	startElement, ok = token.(xml.StartElement)
	if !ok {
		return
	}
	ok = startElement.Name.Local == "row"
	if !ok {
		return
	}
	ok = false
	for _, attr := range startElement.Attr {
		if attr.Name.Local != "r" {
			continue
		}
		row, _ := strconv.Atoi(attr.Value)
		if row == hRow {
			ok = true
			return
		}
	}
	return
}

// Cell can be used directly in StreamWriter.SetRow to specify a style and
// a value.
type Cell struct {
	StyleID int
	Formula string
	Value   interface{}
}

// RowOpts define the options for the set row, it can be used directly in
// StreamWriter.SetRow to specify the style and properties of the row.
type RowOpts struct {
	Height       float64
	Hidden       bool
	StyleID      int
	OutlineLevel int
}

// validateRowOpts checks RowOpts for validity without writing anything.
func (r *RowOpts) validateRowOpts() error {
	if r == nil {
		return nil
	}
	if r.Height > MaxRowHeight {
		return ErrMaxRowHeight
	}
	if r.OutlineLevel > 7 {
		return ErrOutlineLevel
	}
	return nil
}

// marshalAttrs prepare attributes of the row and writes them directly to the
// given bufferedWriter, avoiding intermediate allocations. Caller must call
// validateRowOpts first.
func (r *RowOpts) marshalAttrs(w *bufferedWriter) {
	if r == nil {
		return
	}
	if r.StyleID > 0 {
		w.WriteString(` s="`)
		w.WriteString(strconv.Itoa(r.StyleID))
		w.WriteString(`" customFormat="1"`)
	}
	if r.Height > 0 {
		w.WriteString(` ht="`)
		w.WriteString(strconv.FormatFloat(r.Height, 'f', -1, 64))
		w.WriteString(`" customHeight="1"`)
	}
	if r.OutlineLevel > 0 {
		w.WriteString(` outlineLevel="`)
		w.WriteString(strconv.Itoa(r.OutlineLevel))
		w.WriteString(`"`)
	}
	if r.Hidden {
		w.WriteString(` hidden="1"`)
	}
}

// parseRowOpts provides a function to parse the optional settings for
// *StreamWriter.SetRow.
func parseRowOpts(opts ...RowOpts) RowOpts {
	var options RowOpts
	for _, opt := range opts {
		options = opt
	}
	return options
}

// SetRow writes an array to stream rows by giving starting cell reference and a
// pointer to an array of values. Note that you must call the 'Flush' function
// to end the streaming writing process.
//
// As a special case, if Cell is used as a value, then the Cell.StyleID will be
// applied to that cell.
func (sw *StreamWriter) SetRow(cell string, values []interface{}, opts ...RowOpts) error {
	col, row, err := CellNameToCoordinates(cell)
	if err != nil {
		return err
	}
	if row <= sw.rows {
		return newStreamSetRowError(row)
	}
	sw.rows = row
	sw.writeSheetData()
	options := parseRowOpts(opts...)
	if err = options.validateRowOpts(); err != nil {
		return err
	}
	rowStr := strconv.Itoa(row)
	_, _ = sw.rawData.WriteString(`<row r="`)
	_, _ = sw.rawData.WriteString(rowStr)
	_, _ = sw.rawData.WriteString(`"`)
	options.marshalAttrs(&sw.rawData)
	_, _ = sw.rawData.WriteString(`>`)
	var c xlsxC
	for i, val := range values {
		if val == nil {
			continue
		}
		colIdx := col + i
		if colIdx < MinColumns || colIdx > MaxColumns {
			_, _ = sw.rawData.WriteString(`</row>`)
			return ErrColumnNumber
		}
		style := sw.streamCellStyle(colIdx, options.StyleID)
		// Fast path: write numeric cells directly to the buffer without
		// going through xlsxC.V, eliminating per-cell string allocations.
		if wrote, err := sw.writeNumericCell(val, columnNames[colIdx], rowStr, style); wrote {
			if err != nil {
				_, _ = sw.rawData.WriteString(`</row>`)
				return err
			}
			continue
		}
		// Slow path: complex types go through xlsxC
		c.XMLSpace = xml.Attr{}
		c.T = ""
		c.V = ""
		c.F = nil
		c.IS = nil
		c.S = style
		var s int
		if v, ok := val.(Cell); ok {
			s, val = v.StyleID, v.Value
			setCellFormula(&c, v.Formula)
		} else if v, ok := val.(*Cell); ok && v != nil {
			s, val = v.StyleID, v.Value
			setCellFormula(&c, v.Formula)
		}
		if s > 0 {
			c.S = s
		}
		if err = sw.setCellValFunc(&c, val); err != nil {
			_, _ = sw.rawData.WriteString(`</row>`)
			return err
		}
		writeCell(&sw.rawData, &c, columnNames[colIdx], rowStr)
	}
	_, _ = sw.rawData.WriteString(`</row>`)
	return sw.rawData.Sync()
}

// SetColVisible provides a function set the visibility of a single column or
// multiple columns for the StreamWriter. Note that you must call the
// 'SetColVisible' function before the 'SetRow' function.
//
// For example hide column D:
//
//	err := sw.SetColVisible(4, 4, false)
//
// Hide the columns from D to F (included):
//
//	err := sw.SetColVisible(4, 6, false)
func (sw *StreamWriter) SetColVisible(minVal, maxVal int, visible bool) error {
	if sw.sheetWritten {
		return newStreamSetRowOrderError("SetColVisible")
	}
	if minVal < MinColumns || minVal > MaxColumns || maxVal < MinColumns || maxVal > MaxColumns {
		return ErrColumnNumber
	}
	if minVal > maxVal {
		minVal, maxVal = maxVal, minVal
	}
	sw.worksheet.setColVisible(minVal, maxVal, visible)
	return nil
}

// SetColOutlineLevel provides a function to set outline level of a single
// column for the StreamWriter. The value of parameter 'level' is 1-7. Note that
// you must call the 'SetColOutlineLevel' function before the 'SetRow' function.
// For example, set outline level of column D to 2:
//
//	err := sw.SetColOutlineLevel(4, 2)
func (sw *StreamWriter) SetColOutlineLevel(col int, level uint8) error {
	if sw.sheetWritten {
		return newStreamSetRowOrderError("SetColOutlineLevel")
	}
	if col < MinColumns || col > MaxColumns {
		return ErrColumnNumber
	}
	if level > 7 || level < 1 {
		return ErrOutlineLevel
	}
	sw.worksheet.setColOutlineLevel(col, level)
	return nil
}

// SetColStyle provides a function to set the style of a single column or
// multiple columns for the StreamWriter. Note that you must call
// the 'SetColStyle' function before the 'SetRow' function. For example set
// style of column H:
//
//	err := sw.SetColStyle(8, 8, style)
func (sw *StreamWriter) SetColStyle(minVal, maxVal, styleID int) error {
	if sw.sheetWritten {
		return newStreamSetRowOrderError("SetColStyle")
	}
	if minVal < MinColumns || minVal > MaxColumns || maxVal < MinColumns || maxVal > MaxColumns {
		return ErrColumnNumber
	}
	if maxVal < minVal {
		minVal, maxVal = maxVal, minVal
	}
	s, err := sw.file.stylesReader()
	if err != nil {
		return err
	}
	if styleID < 0 || s.CellXfs == nil || len(s.CellXfs.Xf) <= styleID {
		return newInvalidStyleID(styleID)
	}
	sw.worksheet.setColStyle(minVal, maxVal, styleID)
	return nil
}

// SetColWidth provides a function to set the width of a single column or
// multiple columns for the StreamWriter. Note that you must call
// the 'SetColWidth' function before the 'SetRow' function. For example set
// the width column B:C as 20:
//
//	err := sw.SetColWidth(2, 3, 20)
func (sw *StreamWriter) SetColWidth(minVal, maxVal int, width float64) error {
	if sw.sheetWritten {
		return newStreamSetRowOrderError("SetColWidth")
	}
	if minVal < MinColumns || minVal > MaxColumns || maxVal < MinColumns || maxVal > MaxColumns {
		return ErrColumnNumber
	}
	if width > MaxColumnWidth {
		return ErrColumnWidth
	}
	if minVal > maxVal {
		minVal, maxVal = maxVal, minVal
	}
	sw.worksheet.setColWidth(minVal, maxVal, width)
	return nil
}

// InsertPageBreak creates a page break to determine where the printed page ends
// and where begins the next one by a given cell reference, the content before
// the page break will be printed on one page and after the page break on
// another.
func (sw *StreamWriter) InsertPageBreak(cell string) error {
	return sw.worksheet.insertPageBreak(cell)
}

// SetPanes provides a function to create and remove freeze panes and split
// panes by giving panes options for the StreamWriter. Note that you must call
// the 'SetPanes' function before the 'SetRow' function.
func (sw *StreamWriter) SetPanes(panes *Panes) error {
	if sw.sheetWritten {
		return newStreamSetRowOrderError("SetPanes")
	}
	return sw.worksheet.setPanes(panes)
}

// MergeCell provides a function to merge cells by a given range reference for
// the StreamWriter. Don't create a merged cell that overlaps with another
// existing merged cell.
func (sw *StreamWriter) MergeCell(topLeftCell, bottomRightCell string) error {
	_, err := cellRefsToCoordinates(topLeftCell, bottomRightCell)
	if err != nil {
		return err
	}
	sw.mergeCellsCount++
	_, _ = sw.mergeCells.WriteString(`<mergeCell ref="`)
	_, _ = sw.mergeCells.WriteString(topLeftCell)
	_, _ = sw.mergeCells.WriteString(`:`)
	_, _ = sw.mergeCells.WriteString(bottomRightCell)
	_, _ = sw.mergeCells.WriteString(`"/>`)
	return nil
}

// setCellFormula provides a function to set formula of a cell.
func setCellFormula(c *xlsxC, formula string) {
	if formula != "" {
		c.T, c.F = "str", &xlsxF{Content: formula}
	}
}

// streamCellStyle returns the effective style for a cell in streaming mode.
// It uses the cached column styles array for O(1) lookup instead of scanning
// the column definitions on every cell.
func (sw *StreamWriter) streamCellStyle(col, style int) int {
	if style != 0 {
		return style
	}
	if sw.colStyles != nil && col < len(sw.colStyles) {
		return sw.colStyles[col]
	}
	return style
}

// writeCellStart writes the opening <c> tag with ref and optional style attribute.
func writeCellStart(buf *bufferedWriter, colName, rowStr string, style int) {
	_, _ = buf.WriteString(`<c r="`)
	_, _ = buf.WriteString(colName)
	_, _ = buf.WriteString(rowStr)
	_, _ = buf.WriteString(`"`)
	if style != 0 {
		_, _ = buf.WriteString(` s="`)
		buf.WriteInt(int64(style))
		_, _ = buf.WriteString(`"`)
	}
}

// writeEscaped writes s to buf with XML escaping. If s contains none of the
// five XML special characters (<, >, &, ", \r) it is written directly without
// any allocation. Otherwise it falls back to xml.EscapeText.
func writeEscaped(buf *bufferedWriter, s string) {
	// Fast path: scan for characters that need escaping.
	last := 0
	for i := 0; i < len(s); i++ {
		var esc string
		switch s[i] {
		case '<':
			esc = "&lt;"
		case '>':
			esc = "&gt;"
		case '&':
			esc = "&amp;"
		case '"':
			esc = "&#34;"
		case '\r':
			esc = "&#xD;"
		default:
			continue
		}
		_, _ = buf.WriteString(s[last:i])
		_, _ = buf.WriteString(esc)
		last = i + 1
	}
	_, _ = buf.WriteString(s[last:])
}

// writeNumericCell writes a complete cell element for numeric types (int, uint,
// float, bool) directly to the buffer, bypassing xlsxC and eliminating all
// per-cell heap allocations. Returns (true, nil) if handled, (false, nil) if
// the value type needs the slow path.
func (sw *StreamWriter) writeNumericCell(val interface{}, colName, rowStr string, style int) (bool, error) {
	buf := &sw.rawData
	switch v := val.(type) {
	case int:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteInt(int64(v))
		_, _ = buf.WriteString(`</v></c>`)
	case int8:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteInt(int64(v))
		_, _ = buf.WriteString(`</v></c>`)
	case int16:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteInt(int64(v))
		_, _ = buf.WriteString(`</v></c>`)
	case int32:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteInt(int64(v))
		_, _ = buf.WriteString(`</v></c>`)
	case int64:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteInt(v)
		_, _ = buf.WriteString(`</v></c>`)
	case uint:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteUint(uint64(v))
		_, _ = buf.WriteString(`</v></c>`)
	case uint8:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteUint(uint64(v))
		_, _ = buf.WriteString(`</v></c>`)
	case uint16:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteUint(uint64(v))
		_, _ = buf.WriteString(`</v></c>`)
	case uint32:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteUint(uint64(v))
		_, _ = buf.WriteString(`</v></c>`)
	case uint64:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteUint(v)
		_, _ = buf.WriteString(`</v></c>`)
	case float32:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteFloat(float64(v), 'f', -1, 32)
		_, _ = buf.WriteString(`</v></c>`)
	case float64:
		writeCellStart(buf, colName, rowStr, style)
		_, _ = buf.WriteString(`><v>`)
		buf.WriteFloat(v, 'f', -1, 64)
		_, _ = buf.WriteString(`</v></c>`)
	case bool:
		writeCellStart(buf, colName, rowStr, style)
		if v {
			_, _ = buf.WriteString(` t="b"><v>1</v></c>`)
		} else {
			_, _ = buf.WriteString(` t="b"><v>0</v></c>`)
		}
	default:
		return false, nil
	}
	return true, nil
}

// setCellTime provides a function to set number of a cell with a time.
func (sw *StreamWriter) setCellTime(c *xlsxC, val time.Time) error {
	var date1904, isNum bool
	wb, err := sw.file.workbookReader()
	if err != nil {
		return err
	}
	if wb != nil && wb.WorkbookPr != nil {
		date1904 = wb.WorkbookPr.Date1904
	}
	if isNum, err = c.setCellTime(val, date1904); err == nil && isNum && c.S == 0 {
		style, _ := sw.file.NewStyle(&Style{NumFmt: 22})
		c.S = style
	}
	return nil
}

// setCellValFunc provides a function to set value of a cell.
func (sw *StreamWriter) setCellValFunc(c *xlsxC, val interface{}) error {
	var err error
	switch val := val.(type) {
	case int:
		c.T, c.V = "", strconv.FormatInt(int64(val), 10)
	case int8:
		c.T, c.V = "", strconv.FormatInt(int64(val), 10)
	case int16:
		c.T, c.V = "", strconv.FormatInt(int64(val), 10)
	case int32:
		c.T, c.V = "", strconv.FormatInt(int64(val), 10)
	case int64:
		c.T, c.V = "", strconv.FormatInt(val, 10)
	case uint:
		c.T, c.V = "", strconv.FormatUint(uint64(val), 10)
	case uint8:
		c.T, c.V = "", strconv.FormatUint(uint64(val), 10)
	case uint16:
		c.T, c.V = "", strconv.FormatUint(uint64(val), 10)
	case uint32:
		c.T, c.V = "", strconv.FormatUint(uint64(val), 10)
	case uint64:
		c.T, c.V = "", strconv.FormatUint(val, 10)
	case float32:
		c.setCellFloat(float64(val), -1, 32)
	case float64:
		c.setCellFloat(val, -1, 64)
	case string:
		c.setCellValue(val)
	case []byte:
		c.setCellValue(string(val))
	case time.Duration:
		c.T, c.V = setCellDuration(val)
	case time.Time:
		err = sw.setCellTime(c, val)
	case bool:
		c.T, c.V = setCellBool(val)
	case nil:
		return err
	case []RichTextRun:
		c.T, c.IS = "inlineStr", &xlsxSI{}
		c.IS.R, err = setRichText(val)
	default:
		c.setCellValue(fmt.Sprint(val))
	}
	return err
}

// setCellIntFunc is a wrapper of SetCellInt.
func setCellIntFunc(c *xlsxC, val interface{}) {
	switch val := val.(type) {
	case int:
		c.T, c.V = setCellInt(int64(val))
	case int8:
		c.T, c.V = setCellInt(int64(val))
	case int16:
		c.T, c.V = setCellInt(int64(val))
	case int32:
		c.T, c.V = setCellInt(int64(val))
	case int64:
		c.T, c.V = setCellInt(val)
	case uint:
		c.T, c.V = setCellUint(uint64(val))
	case uint8:
		c.T, c.V = setCellUint(uint64(val))
	case uint16:
		c.T, c.V = setCellUint(uint64(val))
	case uint32:
		c.T, c.V = setCellUint(uint64(val))
	case uint64:
		c.T, c.V = setCellUint(val)
	}
}

// writeCell constructs a cell XML and writes it to the buffer. The colName and
// rowStr parameters provide the pre-computed cell reference components to avoid
// per-cell string allocation.
func writeCell(buf *bufferedWriter, c *xlsxC, colName, rowStr string) {
	_, _ = buf.WriteString(`<c`)
	if c.XMLSpace.Value != "" {
		_, _ = buf.WriteString(` xml:`)
		_, _ = buf.WriteString(c.XMLSpace.Name.Local)
		_, _ = buf.WriteString(`="`)
		_, _ = buf.WriteString(c.XMLSpace.Value)
		_, _ = buf.WriteString(`"`)
	}
	_, _ = buf.WriteString(` r="`)
	_, _ = buf.WriteString(colName)
	_, _ = buf.WriteString(rowStr)
	_, _ = buf.WriteString(`"`)
	if c.S != 0 {
		_, _ = buf.WriteString(` s="`)
		_, _ = buf.WriteString(strconv.Itoa(c.S))
		_, _ = buf.WriteString(`"`)
	}
	if c.T != "" {
		_, _ = buf.WriteString(` t="`)
		_, _ = buf.WriteString(c.T)
		_, _ = buf.WriteString(`"`)
	}
	_, _ = buf.WriteString(`>`)
	if c.F != nil {
		_, _ = buf.WriteString(`<f>`)
		_ = xml.EscapeText(buf, []byte(c.F.Content))
		_, _ = buf.WriteString(`</f>`)
	}
	if c.V != "" {
		_, _ = buf.WriteString(`<v>`)
		if c.T == "" || c.T == "b" {
			// Numeric and boolean values contain only safe characters
			// (digits, '.', '-', '+', 'E', 'e'), skip XML escaping
			_, _ = buf.WriteString(c.V)
		} else {
			writeEscaped(buf, c.V)
		}
		_, _ = buf.WriteString(`</v>`)
	}
	if c.IS != nil {
		if len(c.IS.R) > 0 {
			is, _ := xml.Marshal(c.IS.R)
			_, _ = buf.WriteString(`<is>`)
			_, _ = buf.Write(is)
			_, _ = buf.WriteString(`</is>`)
		}
		if c.IS.T != nil {
			_, _ = buf.WriteString(`<is><t`)
			if c.IS.T.Space.Value != "" {
				_, _ = buf.WriteString(` xml:`)
				_, _ = buf.WriteString(c.IS.T.Space.Name.Local)
				_, _ = buf.WriteString(`="`)
				_, _ = buf.WriteString(c.IS.T.Space.Value)
				_, _ = buf.WriteString(`"`)
			}
			_, _ = buf.WriteString(`>`)
			_, _ = buf.Write([]byte(c.IS.T.Val))
			_, _ = buf.WriteString(`</t></is>`)
		}
	}
	_, _ = buf.WriteString(`</c>`)
}

// writeSheetData prepares the element preceding sheetData and writes the
// sheetData XML start element to the buffer.
func (sw *StreamWriter) writeSheetData() {
	if !sw.sheetWritten {
		bulkAppendFields(&sw.rawData, sw.worksheet, 5, 6)
		if sw.worksheet.Cols != nil {
			// Build column style cache for O(1) per-cell style lookup
			sw.colStyles = make([]int, MaxColumns+1)
			for _, col := range sw.worksheet.Cols.Col {
				if col.Style != 0 {
					for i := col.Min; i <= col.Max; i++ {
						sw.colStyles[i] = col.Style
					}
				}
			}
			_, _ = sw.rawData.WriteString("<cols>")
			for _, col := range sw.worksheet.Cols.Col {
				_, _ = sw.rawData.WriteString(`<col min="`)
				_, _ = sw.rawData.WriteString(strconv.Itoa(col.Min))
				_, _ = sw.rawData.WriteString(`" max="`)
				_, _ = sw.rawData.WriteString(strconv.Itoa(col.Max))
				_, _ = sw.rawData.WriteString(`"`)
				if col.Width != nil {
					_, _ = sw.rawData.WriteString(` width="`)
					_, _ = sw.rawData.WriteString(strconv.FormatFloat(*col.Width, 'f', -1, 64))
					_, _ = sw.rawData.WriteString(`" customWidth="1"`)
				}
				if col.Style != 0 {
					_, _ = sw.rawData.WriteString(` style="`)
					_, _ = sw.rawData.WriteString(strconv.Itoa(col.Style))
					_, _ = sw.rawData.WriteString(`"`)
				}
				if col.Hidden {
					_, _ = sw.rawData.WriteString(` hidden="1"`)
				}
				if col.OutlineLevel > 0 {
					_, _ = sw.rawData.WriteString(` outlineLevel="`)
					_, _ = sw.rawData.WriteString(strconv.FormatUint(uint64(col.OutlineLevel), 10))
					_, _ = sw.rawData.WriteString(`"`)
				}
				_, _ = sw.rawData.WriteString(`/>`)
			}
			_, _ = sw.rawData.WriteString("</cols>")
		}
		_, _ = sw.rawData.WriteString(`<sheetData>`)
		sw.sheetWritten = true
	}
}

// Flush ending the streaming writing process.
func (sw *StreamWriter) Flush() error {
	sw.writeSheetData()
	_, _ = sw.rawData.WriteString(`</sheetData>`)
	bulkAppendFields(&sw.rawData, sw.worksheet, 9, 16)
	mergeCells := strings.Builder{}
	if sw.mergeCellsCount > 0 {
		_, _ = mergeCells.WriteString(`<mergeCells count="`)
		_, _ = mergeCells.WriteString(strconv.Itoa(sw.mergeCellsCount))
		_, _ = mergeCells.WriteString(`">`)
		_, _ = mergeCells.WriteString(sw.mergeCells.String())
		_, _ = mergeCells.WriteString(`</mergeCells>`)
	}
	_, _ = sw.rawData.WriteString(mergeCells.String())
	bulkAppendFields(&sw.rawData, sw.worksheet, 18, 39)
	_, _ = sw.rawData.WriteString(sw.tableParts)
	bulkAppendFields(&sw.rawData, sw.worksheet, 41, 41)
	_, _ = sw.rawData.WriteString(`</worksheet>`)
	if err := sw.rawData.Flush(); err != nil {
		return err
	}

	sheetPath := sw.file.sheetMap[sw.Sheet]
	sw.file.Sheet.Delete(sheetPath)
	sw.file.checked.Delete(sheetPath)
	sw.file.Pkg.Delete(sheetPath)

	return nil
}

// bulkAppendFields bulk-appends fields in a worksheet by specified field
// names order range.
func bulkAppendFields(w io.Writer, ws *xlsxWorksheet, from, to int) {
	s := reflect.ValueOf(ws).Elem()
	enc := xml.NewEncoder(w)
	for i := 0; i < s.NumField(); i++ {
		if from <= i && i <= to {
			_ = enc.Encode(s.Field(i).Interface())
		}
	}
}

// bufferedWriter uses a temp file to store an extended buffer. Initially all
// writes go to an in-memory bytes.Buffer. Once the buffer exceeds the flush
// threshold, it is drained to a temp file and all subsequent writes flow
// through a fixed-size bufio.Writer wrapping the temp file. This bounds peak
// memory to ~bioSize regardless of total data size. Default bioSize is StreamingBufSizeDefault.
type bufferedWriter struct {
	tmpDir    string
	tmp       *os.File
	buf       bytes.Buffer  // used before temp file is created
	bio       *bufio.Writer // used after temp file is created
	scratch   [24]byte      // scratch space for strconv.Append* to avoid heap allocs
	flushSize int           // if >0, flush to temp file at this threshold instead of StreamChunkSize
	bioSize   int           // bufio.Writer buffer size after threshold; 0 = use StreamingBufSizeDefault
}

// Write to the active writer (bufio if streaming, otherwise in-memory buffer).
func (bw *bufferedWriter) Write(p []byte) (n int, err error) {
	if bw.bio != nil {
		return bw.bio.Write(p)
	}
	return bw.buf.Write(p)
}

// WriteString writes to the active writer.
func (bw *bufferedWriter) WriteString(p string) (n int, err error) {
	if bw.bio != nil {
		return bw.bio.WriteString(p)
	}
	return bw.buf.WriteString(p)
}

// WriteInt formats and writes an int64 directly using the scratch space,
// avoiding a heap-allocated string.
func (bw *bufferedWriter) WriteInt(v int64) {
	b := strconv.AppendInt(bw.scratch[:0], v, 10)
	if bw.bio != nil {
		bw.bio.Write(b)
	} else {
		bw.buf.Write(b)
	}
}

// WriteUint formats and writes a uint64 directly to the buffer.
func (bw *bufferedWriter) WriteUint(v uint64) {
	b := strconv.AppendUint(bw.scratch[:0], v, 10)
	if bw.bio != nil {
		bw.bio.Write(b)
	} else {
		bw.buf.Write(b)
	}
}

// WriteFloat formats and writes a float64 directly to the buffer.
func (bw *bufferedWriter) WriteFloat(v float64, fmt byte, prec, bitSize int) {
	b := strconv.AppendFloat(bw.scratch[:0], v, fmt, prec, bitSize)
	if bw.bio != nil {
		bw.bio.Write(b)
	} else {
		bw.buf.Write(b)
	}
}

// Bytes returns the in-memory buffer contents. This is only valid when no
// temp file has been created (i.e. for small worksheets). Once streaming to
// disk, this returns nil.
func (bw *bufferedWriter) Bytes() []byte {
	if bw.tmp != nil {
		return nil
	}
	return bw.buf.Bytes()
}

// Reader provides read-access to the underlying buffer/file.
func (bw *bufferedWriter) Reader() (io.Reader, error) {
	if bw.tmp == nil {
		return bytes.NewReader(bw.buf.Bytes()), nil
	}
	if err := bw.Flush(); err != nil {
		return nil, err
	}
	fi, err := bw.tmp.Stat()
	if err != nil {
		return nil, err
	}
	// os.File.ReadAt does not affect the cursor position and is safe to use here
	return io.NewSectionReader(bw.tmp, 0, fi.Size()), nil
}

// Sync will write the in-memory buffer to a temp file, if the in-memory
// buffer has grown large enough. Once the temp file is created, all
// subsequent writes go through the bufio.Writer and the bytes.Buffer is
// released.
func (bw *bufferedWriter) Sync() (err error) {
	// Already streaming to disk via bufio.Writer — it flushes automatically
	// when its internal buffer is full. Nothing to do here; the final Flush()
	// call will drain any remaining bytes. Forcing a flush on every SetRow
	// would defeat the purpose of the buffer entirely.
	if bw.bio != nil {
		return nil
	}
	if bw.buf.Len() < bw.flushSize {
		return nil
	}
	if bw.tmp == nil {
		bw.tmp, err = os.CreateTemp(bw.tmpDir, "excelize-")
		if err != nil {
			// can not use local storage
			return nil
		}
	}
	// Drain the in-memory buffer to the temp file
	if _, err = bw.buf.WriteTo(bw.tmp); err != nil {
		return err
	}
	// Release the bytes.Buffer backing array entirely
	bw.buf = bytes.Buffer{}
	// Switch to bufio.Writer for all future writes
	bw.bio = bufio.NewWriterSize(bw.tmp, bw.bioSize)
	return nil
}

// Flush ensures all buffered data is written to the temp file.
func (bw *bufferedWriter) Flush() error {
	if bw.tmp == nil {
		return nil
	}
	if bw.bio != nil {
		return bw.bio.Flush()
	}
	_, err := bw.buf.WriteTo(bw.tmp)
	if err != nil {
		return err
	}
	bw.buf = bytes.Buffer{}
	return nil
}

// Reset clears all buffered data (in-memory and bufio) without closing the
// temp file. Used primarily in tests.
func (bw *bufferedWriter) Reset() {
	bw.buf.Reset()
	if bw.bio != nil {
		bw.bio.Reset(&bw.buf) // detach from temp file
		bw.bio = nil
	}
}

// Close the underlying temp file and reset the in-memory buffer.
func (bw *bufferedWriter) Close() error {
	bw.buf.Reset()
	bw.bio = nil
	if bw.tmp == nil {
		return nil
	}
	defer func() {
		_ = os.Remove(bw.tmp.Name())
	}()
	return bw.tmp.Close()
}
